INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0001', 'defect', 'ux', 'Covert Mode Is a Page Navigation, Not a Toggle', 'On the Engineer''s Report, pressing the covert button navigates to /analysis/{id}/view/C (full page load) instead of toggling. User loses scroll position. On non-results pages, the same button does a client-side class toggle.', 'Results page requires server-rendered covert template, so navigation is architecturally necessary. Scroll position loss and inconsistent interaction pattern were unaddressed.', 'activateCovertOrSwitch() uses location.href navigation on analysis pages with no scroll preservation. Fixed by adding sessionStorage save/restore of scrollY.', 1, 0, 'RENDERED', 'ux/covert-toggle-consistency', 1, 'c2b8bab7122d36dd13e92cfcc19ea93bd68218fa9e26c1e89a1838875995a0a4', 'reproduced', 0.95, 'flow', 'conference_demo', '[]'::jsonb, 'T002', 'BSI-001', 'APT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0002', 'design_debt', 'design_system', 'Glass Treatment Only on Posture Cards', 'Glassmorphism CSS selectors only match cards with exact class combination card.border-{status}.bg-{status}.bg-opacity-10. Confidence and Currency cards use card.bg-dark and get no glass treatment or hover-lift.', 'CSS selectors were written for the first card type and never extended to other card patterns.', 'Missing .card.bg-dark glass treatment rule. Fixed by adding glassmorphism and hover-lift to .card.bg-dark selector.', 2, 1, 'RENDERED', 'design/glassmorphism-consistency', 1, '47527c9fcd00f2c6cb6bd34e6951b6716dadb5ad8fd4859739f0cb077a4730d0', 'reproduced', 0.90, 'page', 'critical_path', '[]'::jsonb, 'T002', 'BSI-002', 'APT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0003', 'claim_integrity', 'content', 'Golden Ratio Claim Scope Verification', 'Topology SVG claims golden ratio (320/198 = 1.616 ≈ phi) which is mathematically accurate. CSS type scale uses ad hoc values not derived from phi.', 'Claim may have been broader than implementation.', 'Verified: claim is correctly scoped to topology SVG aria-description only. No system-wide golden ratio claim found in user-facing code.', 2, 2, 'RENDERED', 'content/golden-ratio-claim-scope', 1, 'ab982184426006ab2c3e1c671a04f27bc66537e4caef8b294ea5041c64bda1eb', 'measured', 0.95, 'component', 'edge_case', '[]'::jsonb, 'T005', 'BSI-003', 'APT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0004', 'compliance_gap', 'accessibility', 'No prefers-reduced-motion in CSS', 'Users who set Reduce Motion in OS settings still see every CSS transition, transform, and animation. JavaScript handles topology SVG SMIL but CSS transitions are unprotected.', NULL, 'Missing @media (prefers-reduced-motion: reduce) block. Fixed by adding universal selector that kills animation-duration and transition-duration.', 2, 1, 'RENDERED', 'a11y/prefers-reduced-motion', 1, '97da91606dca883f9650e6fb21cee973323aa6e538c053f82d1a2a05343aaa4e', 'reproduced', 0.95, 'sitewide', 'common', '[{"ref": "2.3.3", "level": "AAA", "scheme": "WCAG"}]'::jsonb, 'T004', 'BSI-004', 'APT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0005', 'compliance_gap', 'accessibility', 'Stats Metric Label 2.1:1 Contrast Ratio', '.stats-confidence-metric-label uses color #484f58 on #161b22 background. Contrast ratio approximately 2.1:1. WCAG AA requires 4.5:1 for normal text.', NULL, 'Hardcoded color too dark. Fixed by changing to #8b949e (5.1:1 contrast ratio).', 2, 1, 'RENDERED', 'a11y/contrast-minimum', 1, '5cd87687c06f7a9de6ad8dd2bd1e2cd4fa8eef2b027fdf5e2644a4fb96ee3cb7', 'measured', 0.99, 'page', 'common', '[{"ref": "1.4.3", "level": "AA", "scheme": "WCAG"}]'::jsonb, 'T003', 'BSI-005', 'APT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0006', 'compliance_gap', 'accessibility', 'Compare Select Rows Keyboard Inaccessible', 'Domain comparison rows use click handlers on bare tr elements. No tabindex, no role, no aria-label. Keyboard-only users cannot reach or activate these rows.', NULL, 'Missing keyboard accessibility attributes. Fixed by adding tabindex=0, role=button, aria-label, and Enter/Space keydown handler.', 1, 0, 'RENDERED', 'a11y/keyboard-accessible-interactive', 1, '6d30148fe3e19413d347b07a9290deda3dd16b457d9f40141486bd054d775b88', 'reproduced', 0.99, 'page', 'common', '[{"ref": "2.1.1", "level": "A", "scheme": "WCAG"}]'::jsonb, 'T003', 'BSI-006', 'APT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0007', 'defect', 'content', 'Architecture Page SVG Diagrams 404', 'Two SVG diagrams (drift-notification-pipeline.svg and github-issues-triage.svg) reported as returning 404 on the architecture page.', 'Files may have been missing from static/images/diagrams/ directory.', 'Files exist and serve HTTP 200. Issue was previously resolved.', 2, 1, 'RENDERED', 'content/broken-asset-links', 1, '1df827ff2fda8938de482a9fc09776cd6e6c571be42edc3011c6af6091fcaaec', 'measured', 0.99, 'page', 'conference_demo', '[]'::jsonb, 'T001', 'BSI-007', 'APT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0008', 'compliance_gap', 'accessibility', 'Copy Buttons Mouse-Only Visibility', '.copy-btn has opacity: 0 by default and only becomes visible on :hover. Keyboard-only users never see the button and cannot focus on an invisible element.', NULL, 'Missing keyboard focus reveal. Fixed by adding :focus-within and :focus selectors alongside :hover for opacity:1.', 2, 1, 'RENDERED', 'a11y/keyboard-visible-interactive', 1, '16405d18f4fecbff255ff490f54f826304b3b8c588e08af91933cf63fa22f51a', 'reproduced', 0.99, 'sitewide', 'common', '[{"ref": "2.1.1", "level": "A", "scheme": "WCAG"}, {"ref": "2.4.7", "level": "AA", "scheme": "WCAG"}]'::jsonb, 'T002', 'BSI-008', 'APT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0009', 'defect', 'ux', 'Anchor Scroll Handler Hijacks Bootstrap Collapse', 'A generic smooth-scroll handler on ALL a[href^="#"] links calls e.preventDefault(), blocking Bootstrap collapse triggers that use href="#target" instead of data-bs-target.', 'Bootstrap collapse relies on default click behavior which is being intercepted.', NULL, 2, 1, 'DETAINED', 'ux/scroll-handler-bootstrap-conflict', 1, '67bba28334558ba589ecf7a707d0551996bbf54182eecfb12ec888747c25c1c6', 'reproduced', 0.90, 'flow', 'common', '[]'::jsonb, 'T002', 'BSI-009', 'ZERO-DAY') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0010', 'defect', 'ux', 'white-space-nowrap Class Does Not Exist', 'Template uses CSS class white-space-nowrap which does not exist in Bootstrap or custom CSS. The intended class is text-nowrap.', NULL, NULL, 3, 2, 'DETAINED', 'ux/nonexistent-css-class', 1, '62e1dacdfa1e935fb5da847f2c1e1577ee53e8ac70157e6f1a1252205b443f87', 'static_analysis', 0.99, 'component', 'edge_case', '[]'::jsonb, 'T002', 'BSI-010', 'ZERO-DAY') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0011', 'defect', 'design_system', 'border-accent-gold-muted Class Does Not Exist', 'Currency card references border-accent-gold-muted as a CSS class. No CSS rule exists for this class. Border color falls back to default.', NULL, NULL, 3, 2, 'DETAINED', 'design/nonexistent-css-class', 1, '1a1ae688859dd3f1acca1222206a9aac4bae45a02cb0a564ec126fc79c375590', 'static_analysis', 0.99, 'page', 'critical_path', '[]'::jsonb, 'T002', 'BSI-011', 'ZERO-DAY') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0012', 'defect', 'ux', 'DNS Hosting Column Missing text-truncate', 'In Domain Summary, Registrar/Email/Web Hosting columns use text-truncate. DNS Hosting column does not. Long provider names overflow on mobile.', NULL, NULL, 3, 2, 'DETAINED', 'ux/text-truncate-consistency', 1, '25b9b747a893e2665ad9983da917d96d90cd43ff12232a1d6387894872db27f2', 'reproduced', 0.90, 'component', 'common', '[]'::jsonb, 'T002', 'BSI-012', 'EXPLOIT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0013', 'defect', 'ux', 'Chevron Icons Never Rotate on Collapse', 'Chevron-down icons remain pointing down regardless of panel state. Users get no visual feedback about whether a section is open or closed.', 'Missing CSS transform or JS toggle for chevron rotation on Bootstrap collapse events.', NULL, 3, 2, 'DETAINED', 'ux/collapse-chevron-rotation', 1, '2352d6935eb6be5132dc18ba9dcc3215af0837098b88da00fad2e918cd73a812', 'reproduced', 0.90, 'flow', 'common', '[]'::jsonb, 'T002', 'BSI-013', 'EXPLOIT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0014', 'defect', 'ux', 'Tooltips Only Work on Results Pages', 'Bootstrap tooltip initialization happens only in inline script inside results.html. Global main.js has no tooltip init. Tooltips on other pages do nothing.', NULL, NULL, 3, 2, 'DETAINED', 'ux/tooltip-initialization-scope', 1, '37902edd594bc4b9b530840de5a9a013c182d44f2b6bc08d4357fe086245b757', 'reproduced', 0.90, 'sitewide', 'common', '[]'::jsonb, 'T002', 'BSI-014', 'EXPLOIT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0015', 'defect', 'ux', 'Mobile Navbar Menu Extends Below Viewport', 'Navbar collapse dropdown uses position: absolute with no max-height and no overflow-y: auto. With 11+ nav items on shorter mobile screens, menu extends below viewport.', NULL, NULL, 2, 1, 'DETAINED', 'ux/navbar-mobile-overflow', 1, '262dc6e608f355a5341f956edd137b65a68522cae2ae05e60213b2a65eab830c', 'reproduced', 0.85, 'sitewide', 'common', '[]'::jsonb, 'T003', 'BSI-015', 'EXPLOIT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0016', 'design_debt', 'ux', 'Footer Wall of Text at 375px', 'Ten or more footer links in a single p tag separated by middot dots. At 375px this renders as unstructured wall of text with no grouping.', NULL, NULL, 3, 2, 'DETAINED', 'ux/footer-mobile-layout', 1, 'b788bcb54153314f87283dfc4335f06798dc70a864d15c525af2635e9482904f', 'reproduced', 0.85, 'sitewide', 'common', '[]'::jsonb, 'T003', 'BSI-016', 'EXPLOIT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0017', 'defect', 'seo', 'Video Category Score F (57/100)', 'SquirrelScan video category scored 57/100. Likely missing VideoObject structured data, accessibility attributes, poster images, or proper preload configuration.', 'Multiple video optimization best practices not implemented.', NULL, 3, 2, 'DETAINED', 'seo/video-optimization', 1, 'dfd32e2779095ec16c97c38fe440c43df7835a51511c0de50c914346c6fcf2e5', 'static_analysis', 0.75, 'sitewide', 'internal', '[]'::jsonb, 'T001', 'BSI-017', 'EXPLOIT') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0018a', 'weakness', 'security', 'OAuth Client ID Exposed in Page Source', 'Google OAuth Client ID visible in inline script on login page. Google documents client IDs as not secret and exposed to resource owners.', 'Standard OAuth2 flow requires client_id in browser. This is hygiene, not a vulnerability.', NULL, 4, 3, 'DETAINED', 'security/oauth-client-id-exposure', 1, '37f4b366de8ca6bc07bbdcebc096ee12b6ed1524976a934223b615b77108eff3', 'static_analysis', 0.80, 'page', 'edge_case', '[{"ref": "RFC6749-2.2", "scheme": "OAuth2"}]'::jsonb, 'T001', 'BSI-018', 'ZERO-DAY') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0018b', 'incident', 'security', 'Sanity Token Exposed in HTML', 'A Sanity Token exposed in analysis view HTML. Sanity documents tokens as credentials that should generally be considered secret. Browser-exposed tokens are a bad idea.', 'Token may be a read-only public dataset token, but exposure should be verified and scoped.', NULL, 1, 0, 'DETAINED', 'security/token-exposure-html', 1, 'cdfde6065c61f8f52d0f64ea10374b227c933f5db7842fcfc60d7ee2f45696e6', 'static_analysis', 0.85, 'page', 'common', '[]'::jsonb, 'T001', 'BSI-018', 'ZERO-DAY') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0019', 'weakness', 'security', 'CSP script-src Allows Wildcard', 'The script-src directive uses *, allowing JavaScript execution from any origin. This effectively disables browser-side XSS defense.', NULL, NULL, 1, 0, 'DETAINED', 'security/csp-script-src-wildcard', 1, 'f1ae484acbbd923f08a4e9ec5f44cd7b233505c25f65e7dc70ac511b60b14605', 'measured', 0.99, 'sitewide', 'common', '[{"ref": "Level-3", "scheme": "CSP"}]'::jsonb, 'T001', 'BSI-019', 'ZERO-DAY') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0020', 'design_debt', 'design_system', '908 !important Declarations', '~908 !important declarations, ~450 in covert mode alone. Architecturally inevitable without CSS @layer. Every future style must also use !important.', 'CSS @layer would resolve the specificity arms race. Supported since March 2022.', NULL, 2, 2, 'DETAINED', 'design/important-declarations-count', 1, '350c412d17daf99d33bc1444a3d7112d44f3a2745e25a66d3f617302e9eaed55', 'measured', 0.95, 'sitewide', 'internal', '[]'::jsonb, 'T004', 'BSI-020', 'CVE') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0021', 'design_debt', 'design_system', '50+ Hardcoded Hex Colors Outside Token System', 'Documented 5-layer color architecture with CSS custom properties exists. But 50+ hex values bypass it entirely.', NULL, NULL, 3, 2, 'DETAINED', 'design/color-token-bypass', 1, '4c14b1cd7c18fccba095b18bce3e16e86696dbe52056dc8373003c6b4d99c5bb', 'static_analysis', 0.90, 'sitewide', 'internal', '[]'::jsonb, 'T004', 'BSI-021', 'CVE') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0022', 'design_debt', 'design_system', 'Blur Radius Has 4 Values No Design Token', 'backdrop-filter uses 12px, 8px, 6px, 4px across components with no documented rationale. No --blur-* design tokens.', NULL, NULL, 4, 3, 'DETAINED', 'design/blur-radius-token', 1, 'd4ade2b11aa5835d776bbad424ec60cf8caa1409ab604f522b6bd7d02777eca5', 'static_analysis', 0.85, 'sitewide', 'internal', '[]'::jsonb, 'T004', 'BSI-022', 'CVE') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0023', 'design_debt', 'design_system', '5+ Transition Timing Values No System', '0.15s, 0.2s, 0.25s, 0.3s, 0.35s — five different transition speeds across interactive elements. No transition design tokens.', NULL, NULL, 4, 3, 'DETAINED', 'design/transition-timing-token', 1, '29cef05e4723bf6906a362a7836a34ca22a1fb87f2cae5a74333936dfec5cfb0', 'static_analysis', 0.85, 'sitewide', 'internal', '[]'::jsonb, 'T004', 'BSI-023', 'CVE') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0024', 'defect', 'performance', 'transition: all Animates Every CSS Property', 'transition: all 0.2s ease animates width, height, box-shadow, and layout-triggering properties causing unnecessary GPU work.', NULL, NULL, 3, 2, 'DETAINED', 'perf/transition-all', 1, '730efafc4fe8b21e2d19cc4f54819cd6a2e914b6cab0ffed55ef705fac71e24a', 'static_analysis', 0.90, 'sitewide', 'internal', '[]'::jsonb, 'T004', 'BSI-024', 'CVE') ON CONFLICT (public_id) DO NOTHING;
INSERT INTO findings (public_id, kind, domain, title, symptom_md, hypothesis_md, root_cause_md, severity, priority, status, canonical_rule_id, fingerprint_version, fingerprint_sha256, evidence_grade, confidence, blast_radius, visibility, standard_refs, source_team, legacy_bsi_id, legacy_threat_level) VALUES ('BSI-2026-0025', 'design_debt', 'design_system', 'Three Syntaxes for Same Breakpoint', 'Mixes max-width: 767px, 767.98px, and 768px — three different expressions for the same mobile/tablet boundary.', NULL, NULL, 4, 3, 'DETAINED', 'design/breakpoint-syntax-consistency', 1, '10a225183d557e0631b7867ed52fa0a87e75d9889abbd05d8af8d1084ad28435', 'static_analysis', 0.95, 'sitewide', 'internal', '[]'::jsonb, 'T004', 'BSI-025', 'CVE') ON CONFLICT (public_id) DO NOTHING;
